    it.todo("should return 85G for a single plain staff (80G base + 5G fee)");
    it.todo("should return 45G for a single plain potion (40G base + 5G fee)");
    it.todo("should return 165G for a plain sword and plain amulet (100+60 + 5G fee)");
  });

  describe("Quote - components", () => {
    it.todo("should return 55G for 2 runes (2×25 + 5G fee)");
