    it.todo("should return 125G for 3 runes + 3 moonstones (two separate blocks, 120 + 5G fee)");
  });

  describe("Quote - item-level modifiers", () => {
    it.todo("should add 50% cursed surcharge to cursed item only");
    it.todo("should add 30% high-enchantment surcharge for enchantment >= 5");
