    it.todo("should not add high-enchantment surcharge for enchantment 4");
    it.todo("should apply cursed surcharge only to cursed item in multi-item policy");
  });

  describe("Quote - policy-level modifiers", () => {
    it.todo("should apply 20% loyalty discount for customer with >= 2 years");
    it.todo("should apply 10% first insurance surcharge (always applies)");
