const BASE_PREMIUMS: Record<string, number> = {
  sword: 100,
  amulet: 60,
  staff: 80,
  potion: 40,
  rune: 25,
  moonstone: 25,
};

const PROCESSING_FEE = 5;
const COMPONENT_TYPES = new Set(["rune", "moonstone"]);
const BLOCK_PREMIUM = 60;

function calculateQuotePremium(items: any[]): number {
  let premium = 0;
  const componentCounts: Record<string, number> = {};
  for (const item of items) {
    if (COMPONENT_TYPES.has(item.type)) {
      componentCounts[item.type] = (componentCounts[item.type] ?? 0) + 1;
    } else {
      const basePremium = BASE_PREMIUMS[item.type] ?? 0;
      premium += basePremium;
      if (item.cursed) {
        premium += basePremium * 0.5;
      }
    }
  }
  for (const [type, count] of Object.entries(componentCounts)) {
    if (count === 3) {
      premium += BLOCK_PREMIUM;
    } else {
      premium += count * (BASE_PREMIUMS[type] ?? 0);
    }
  }
  premium += PROCESSING_FEE;
  return premium;
}

export function processScenario(scenario: any): any {
  const results = scenario.steps.map((step: any) => {
    if (step.op === "quote") {
      return { premium: calculateQuotePremium(step.items) };
    }
  });
  return { results };
}

