import { describe, it, expect } from "vitest";
import { processScenario } from "./claim-office.js";

describe("MHPCO Claim Office", () => {
  describe("Quote - base premiums", () => {
    it("should return 5G premium for empty item list (processing fee only)", () => {
      const result = processScenario({
        customer: { yearsWithMHPCO: 0 },
        steps: [{ op: "quote" as const, items: [] }],
      });
      expect(result.results[0]).toEqual({ premium: 5 });
    });
    it("should return 105G for a single plain sword (100G base + 5G fee)", () => {
      const result = processScenario({
        customer: { yearsWithMHPCO: 0 },
        steps: [
          {
            op: "quote" as const,
            items: [
              { type: "sword", material: "steel", enchantment: 0, cursed: false },
            ],
          },
        ],
      });
      expect(result.results[0]).toEqual({ premium: 105 });
    });
    it("should return 65G for a single plain amulet (60G base + 5G fee)", () => {
      const result = processScenario({
        customer: { yearsWithMHPCO: 0 },
        steps: [
          {
            op: "quote" as const,
            items: [
              { type: "amulet", material: "silver", enchantment: 0, cursed: false },
            ],
          },
        ],
      });
      expect(result.results[0]).toEqual({ premium: 65 });
    });
    it("should return 85G for a single plain staff (80G base + 5G fee)", () => {
      const result = processScenario({
        customer: { yearsWithMHPCO: 0 },
        steps: [
          {
            op: "quote" as const,
            items: [
              { type: "staff", material: "wood", enchantment: 0, cursed: false },
            ],
          },
        ],
      });
      expect(result.results[0]).toEqual({ premium: 85 });
    });
    it("should return 45G for a single plain potion (40G base + 5G fee)", () => {
      const result = processScenario({
        customer: { yearsWithMHPCO: 0 },
        steps: [
          {
            op: "quote" as const,
            items: [
              { type: "potion", material: "glass", enchantment: 0, cursed: false },
            ],
          },
        ],
      });
      expect(result.results[0]).toEqual({ premium: 45 });
    });
    it("should return 165G for a plain sword and plain amulet (100+60 + 5G fee)", () => {
      const result = processScenario({
        customer: { yearsWithMHPCO: 0 },
        steps: [
          {
            op: "quote" as const,
            items: [
              { type: "sword", material: "steel", enchantment: 0, cursed: false },
              { type: "amulet", material: "silver", enchantment: 0, cursed: false },
            ],
          },
        ],
      });
      expect(result.results[0]).toEqual({ premium: 165 });
    });
  });

  describe("Quote - components", () => {
    it("should return 55G for 2 runes (2×25 + 5G fee)", () => {
      const result = processScenario({
        customer: { yearsWithMHPCO: 0 },
        steps: [
          {
            op: "quote" as const,
            items: [
              { type: "rune" },
              { type: "rune" },
            ],
          },
        ],
      });
      expect(result.results[0]).toEqual({ premium: 55 });
    });
    it("should return 65G for 3 runes (block of 3 alike = 60 + 5G fee)", () => {
      const result = processScenario({
        customer: { yearsWithMHPCO: 0 },
        steps: [
          {
            op: "quote" as const,
            items: [
              { type: "rune" },
              { type: "rune" },
              { type: "rune" },
            ],
          },
        ],
      });
      expect(result.results[0]).toEqual({ premium: 65 });
    });
    it("should return 105G for 4 runes (4×25 = 100 + 5G fee, no block)", () => {
      const result = processScenario({
        customer: { yearsWithMHPCO: 0 },
        steps: [
          {
            op: "quote" as const,
            items: [
              { type: "rune" },
              { type: "rune" },
              { type: "rune" },
              { type: "rune" },
            ],
          },
        ],
      });
      expect(result.results[0]).toEqual({ premium: 105 });
    });
    it("should return 180G for 7 runes (7×25 = 175 + 5G fee)", () => {
      const result = processScenario({
        customer: { yearsWithMHPCO: 0 },
        steps: [
          {
            op: "quote" as const,
            items: Array.from({ length: 7 }, () => ({ type: "rune" })),
          },
        ],
      });
      expect(result.results[0]).toEqual({ premium: 180 });
    });
    it("should return 80G for 2 runes + 1 moonstone (no block: different types, 75 + 5G fee)", () => {
      const result = processScenario({
        customer: { yearsWithMHPCO: 0 },
        steps: [
          {
            op: "quote" as const,
            items: [
              { type: "rune" },
              { type: "rune" },
              { type: "moonstone" },
            ],
          },
        ],
      });
      expect(result.results[0]).toEqual({ premium: 80 });
    });
    it("should return 125G for 3 runes + 3 moonstones (two separate blocks, 120 + 5G fee)", () => {
      const result = processScenario({
        customer: { yearsWithMHPCO: 0 },
        steps: [
          {
            op: "quote" as const,
            items: [
              { type: "rune" },
              { type: "rune" },
              { type: "rune" },
              { type: "moonstone" },
              { type: "moonstone" },
              { type: "moonstone" },
            ],
          },
        ],
      });
      expect(result.results[0]).toEqual({ premium: 125 });
    });
  });

  describe("Quote - item-level modifiers", () => {
    it("should add 50% cursed surcharge to cursed item only", () => {
      const result = processScenario({
        customer: { yearsWithMHPCO: 0 },
        steps: [
          {
            op: "quote" as const,
            items: [
              { type: "sword", material: "steel", enchantment: 0, cursed: true },
            ],
          },
        ],
      });
      // 100 base + 50 curse surcharge + 5 fee = 155
      expect(result.results[0]).toEqual({ premium: 155 });
    });
    it("should add 30% high-enchantment surcharge for enchantment >= 5", () => {
      const result = processScenario({
        customer: { yearsWithMHPCO: 0 },
        steps: [
          {
            op: "quote" as const,
            items: [
              { type: "sword", material: "steel", enchantment: 5, cursed: false },
            ],
          },
        ],
      });
      // 100 base + 30 high-enchantment surcharge + 5 fee = 135
      expect(result.results[0]).toEqual({ premium: 135 });
    });
    it("should apply both cursed and high-enchantment surcharges on same item", () => {
      const result = processScenario({
        customer: { yearsWithMHPCO: 0 },
        steps: [
          {
            op: "quote" as const,
            items: [
              { type: "sword", material: "steel", enchantment: 5, cursed: true },
            ],
          },
        ],
      });
      // 100 base + 50 curse + 30 enchantment + 5 fee = 185
      expect(result.results[0]).toEqual({ premium: 185 });
    });
    it("should not add high-enchantment surcharge for enchantment 4", () => {
      const result = processScenario({
        customer: { yearsWithMHPCO: 0 },
        steps: [
          {
            op: "quote" as const,
            items: [
              { type: "sword", material: "steel", enchantment: 4, cursed: false },
            ],
          },
        ],
      });
      // 100 base + 5 fee = 105 (no enchantment surcharge)
      expect(result.results[0]).toEqual({ premium: 105 });
    });
    it("should apply cursed surcharge only to cursed item in multi-item policy", () => {
      const result = processScenario({
        customer: { yearsWithMHPCO: 0 },
        steps: [
          {
            op: "quote" as const,
            items: [
              { type: "sword", material: "steel", enchantment: 0, cursed: true },
              { type: "amulet", material: "silver", enchantment: 0, cursed: false },
            ],
          },
        ],
      });
      // 100 base sword + 50 curse on sword + 60 base amulet + 5 fee = 215
      expect(result.results[0]).toEqual({ premium: 215 });
    });
  });

  describe("Quote - policy-level modifiers", () => {
    it("should apply 20% loyalty discount for customer with >= 2 years", () => {
      const result = processScenario({
        customer: { yearsWithMHPCO: 2 },
        steps: [
          {
            op: "quote" as const,
            items: [
              { type: "sword", material: "steel", enchantment: 0, cursed: false },
            ],
          },
        ],
      });
      // 100 base - 20 loyalty discount + 5 fee = 85
      expect(result.results[0]).toEqual({ premium: 85 });
    });
    it("should apply 10% first insurance surcharge (always applies)", () => {
      const result = processScenario({
        customer: { yearsWithMHPCO: 0 },
        steps: [
          {
            op: "quote" as const,
            items: [
              { type: "sword", material: "steel", enchantment: 0, cursed: false },
            ],
          },
        ],
      });
      // 100 base + 10 first insurance (10% of 100) + 5 fee = 115
      expect(result.results[0]).toEqual({ premium: 115 });
    });
    it.todo("should apply 15% follow-up discount on second quote");
  });

  describe("Quote - integration", () => {
    it.todo("should compute 165G for newcomer with cursed sword (100 base + 50 curse + 10 first ins + 5 fee)");
    it.todo("should compute 160G for long-standing customer second contract with cursed enchanted sword");
    it.todo("should round premium up in MHPCO's favor");
  });

  describe("Claim - basic reimbursement", () => {
    it.todo("should apply 100G deductible per damaged item");
    it.todo("should fully reimburse regular item damage minus deductible");
    it.todo("should reimburse component damage minus deductible");
  });

  describe("Claim - special clauses", () => {
    it.todo("should reimburse at 50% for enchantment >= 8, then deductible");
    it.todo("should fully reimburse dragon material items, then deductible");
    it.todo("should apply 50% rule when both dragon material and enchantment >= 8");
    it.todo("should fully reimburse dragon material with enchantment < 8, then deductible");
  });

  describe("Claim - cap", () => {
    it.todo("should cap total payout at 2x insurance sum");
    it.todo("should track remaining cap across multiple claims");
    it.todo("should reduce payout to remaining cap when cap is nearly exhausted");
  });

  describe("Claim - multiple damages in one event", () => {
    it.todo("should apply deductible per damaged item in multi-damage event");
    it.todo("should handle two items of same type insured and damaged separately");
  });

  describe("Error handling", () => {
    it.todo("should reject unknown item type in quote");
    it.todo("should reject claim referencing uninsured item type");
    it.todo("should reject negative damage amount");
    it.todo("should reject more damages of a type than insured");
  });

  describe("CLI", () => {
    it.todo("should read JSON from stdin and write results to stdout");
    it.todo("should exit with non-zero status on error and write to stderr");
  });
});

