export function processScenario(scenario: any): any {
  let quoteCount = 0;
  const policies: any[] = [];
  const results = scenario.steps.map((step: any) => {
    if (step.op === "quote") {
      const isFollowUp = quoteCount > 0;
      quoteCount++;
      policies.push({ items: step.items });
      return { premium: calculateQuotePremium(step.items, scenario.customer, isFollowUp) };
    }
    if (step.op === "claim") {
      const policy = policies[step.policy];
      let insuranceSum = 0;
      for (const item of policy.items) {
        insuranceSum += INSURANCE_VALUES[item.type] ?? 0;
      }
      const cap = 2 * insuranceSum;
      let totalPayout = 0;
      for (const damage of step.incident.damages) {
        const payout = damage.amount - DEDUCTIBLE;
        totalPayout += Math.max(0, payout);
      }
      totalPayout = Math.min(totalPayout, cap);
      return { payout: totalPayout, remainingCap: cap - totalPayout };
    }
  });
  return { results };
}

